import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it("should return 5 G processing fee for empty item list", () => {
      expect(quote({ items: [], customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(5);
    });
    it("should return base premium plus fee for a single sword", () => {
      expect(quote({ items: [{ type: "sword" }], customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(105);
    });
    it("should return base premium plus fee for a single amulet", () => {
      expect(quote({ items: [{ type: "amulet" }], customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(65);
    });
    it("should return base premium plus fee for a single staff", () => {
      expect(quote({ items: [{ type: "staff" }], customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(85);
    });
    it("should return base premium plus fee for a single potion", () => {
      expect(quote({ items: [{ type: "potion" }], customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(45);
    });
    it("should return base premium plus fee for a single component (rune)", () => {
      expect(quote({ items: [{ type: "rune" }], customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(30);
    });
    it("should return 60 G base premium for a block of 3 alike components", () => {
      const items = [{ type: "rune" }, { type: "rune" }, { type: "rune" }];
      expect(quote({ items, customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(65);
    });
    it("should not apply block discount for 2 alike components", () => {
      const items = [{ type: "rune" }, { type: "rune" }];
      expect(quote({ items, customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(55);
    });
    it("should not apply block discount for 4 alike components", () => {
      const items = [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }];
      expect(quote({ items, customer: { yearsWithMHPCO: 0, contractCount: 0 } })).toBe(105);
    });
    it("should apply cursed surcharge (50%) to the cursed item only", () => {
      // Cursed sword: 100G base + 50G curse surcharge = 150G policy base + 5G fee = 155G
      // (no other modifiers in this test)
      const items = [{ type: "sword", cursed: true }];
      const customer = { yearsWithMHPCO: 0, contractCount: 0 };
      expect(quote({ items, customer })).toBe(155);
    });
    it("should apply high enchantment surcharge (30%) for enchantment level >= 5", () => {
      // Sword with enchantment 5: 100G base + 30G high-enchantment surcharge = 130G + 5G fee = 135G
      const items = [{ type: "sword", enchantment: 5 }];
