export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Customer = {
  yearsWithMHPCO: number;
  contractCount: number;
};

export type QuoteInput = {
  items: Item[];
  customer: Customer;
};

const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const isAlikeBlock = (items: Item[]): boolean =>
  items.length === 3 && items.every(i => i.type === items[0].type);

const itemPremium = (item: Item): number => {
  const curseMultiplier = item.cursed ? 1.5 : 1;
  const enchantmentMultiplier = (item.enchantment ?? 0) >= 5 ? 1.3 : 1;
  return BASE_PREMIUMS[item.type] * curseMultiplier * enchantmentMultiplier;
};

const basePremium = (items: Item[]): number => {
  if (isAlikeBlock(items)) return COMPONENT_BLOCK_PREMIUM;
  return items.reduce((sum, item) => sum + itemPremium(item), 0);
};

export const quote = ({ items, customer }: QuoteInput): number => {
  const base = basePremium(items);
  const loyaltyMultiplier = customer.yearsWithMHPCO >= 2 ? 0.8 : 1;
  const firstInsuranceSurcharge = customer.contractCount === 0 ? base * 0.1 : 0;
  const followUpDiscount = customer.contractCount >= 1 ? base * 0.15 : 0;
  return base * loyaltyMultiplier + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type Policy = {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
};

