      // 180 - 20 + 10 - 15 = 155G + 5G fee = 160G
      const items = [{ type: "sword", cursed: true, enchantment: 7 }];
      const customer = { yearsWithMHPCO: 3, contractCount: 1 };
      expect(quote({ items, customer })).toBe(160);
    });
