      expect(second.payout).toBe(600);
      expect(second.remainingCap).toBe(0);
    });
    it("should apply deductible once per damaged item in multi-item events", () => {
      // Dragon attack: sword damaged 500G and amulet damaged 300G
      // sword: 500 - 100 = 400G; amulet: 300 - 100 = 200G; total payout = 600G
      const policy = {
        items: [{ type: "sword" }, { type: "amulet" }],
        insuranceSum: 1600,
        remainingCap: 3200,
      };
      const incident = {
        cause: "dragon attack",
        damages: [
          { itemType: "sword", amount: 500 },
          { itemType: "amulet", amount: 300 },
        ],
      };
      const result = claim({ policy, incident });
      expect(result.payout).toBe(600);
      expect(result.remainingCap).toBe(2600);
    });
    it.todo("should round payout down (MHPCO's favor)");
    it.todo("should exit with non-zero status for damage referencing item not in policy");
    it.todo("should exit with non-zero status for negative damage amount");
    it.todo("should exit with non-zero status when damages exceed insured items of same type");
  });
});

