      // Second claim: 1500 - 100 = 1400G raw, capped to 600G, remainingCap = 0G
      const policy = { items: [{ type: "sword" }], insuranceSum: 1000, remainingCap: 2000 };
      const incident = { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] };
